package com.example.cms.operations.deployment; import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.stereotype.Service;import java.util.*; @Service public class DeploymentService{private final JdbcTemplate jdbc; public DeploymentService(JdbcTemplate jdbc){this.jdbc=jdbc;} public List<Map<String,Object>> list(){return jdbc.queryForList("select * from deployment_records order by deployed_at desc");}}
